     1→/**
     2→ * Unit Tests for AI Routing Stage
     3→ *
     4→ * Following TDD approach - these tests MUST FAIL before implementation.
     5→ * This stage determines whether emails need AI classification based on confidence scores.
     6→ */
     7→
     8→import { aiRoutingStage } from '../../src/stages/ai-routing';
     9→import { CandidateScore } from '../../src/types/classification-result';
    10→import { EmailMessage, ClassificationSession } from '../../src/types';
    11→import { createClassificationResult } from '../../src/utils/initialization';
    12→
    13→describe('AI Routing Stage', () => {
    14→  const mockConfig = {
    15→    settings: {
    16→      aiRouting: {
    17→        highConfidenceThreshold: 15,
    18→        aiRequiredThreshold: 12,
    19→        skipAiConditions: ['hardAssertion'],
    20→      },
    21→    },
    22→    confidenceThresholds: {
    23→      highConfidence: 15,
    24→      mediumConfidence: 8,
    25→      lowConfidence: 3,
    26→      secondaryLabelMinGap: 5,
    27→      aiClassificationRequired: 12,
    28→    },
    29→  };
    30→
    31→  const mockEmail: EmailMessage = {
    32→    id: 'test-123',
    33→    threadId: 'thread-123',
    34→    gmailLabels: [],
    35→    payload: {
    36→      mimeType: 'text/plain',
    37→      headers: [
    38→        { name: 'Subject', value: 'Test email' },
    39→        { name: 'From', value: 'Test User <test@example.com>' },
    40→        { name: 'To', value: 'User <user@example.com>' },
    41→      ],
    42→    },
    43→    subject: 'Test email',
    44→    from: { email: 'test@example.com', name: 'Test User', raw: 'Test User <test@example.com>' },
    45→    to: [{ email: 'user@example.com', name: 'User', raw: 'User <user@example.com>' }],
    46→    bodyPlain: 'Test email body',
    47→    bodyHtml: '<p>Test email body</p>',
    48→    date: new Date('2024-01-01T10:00:00Z'),
    49→    isProcessed: false,
    50→    processingPriority: 1,
    51→  };
    52→
    53→  const mockSession: ClassificationSession = {
    54→    id: 'session-123',
    55→    startedAt: new Date('2024-01-01T10:00:00Z'),
    56→    emailCount: 1,
    57→    successCount: 0,
    58→    errorCount: 0,
    59→    processingMode: 'parallel',
    60→    batchSize: 1,
    61→    performanceMetrics: {
    62→      totalDurationMs: 0,
    63→      avgEmailDurationMs: 0,
    64→      parallelStagesCount: 0,
    65→      databaseBatchOps: 0,
    66→    },
    67→    configVersion: 'test-version',
    68→    configSnapshot: {},
    69→    errors: [],
    70→    warnings: [],
    71→  };
    72→
    73→  describe('High Confidence Routing', () => {
    74→    it('should skip AI for high confidence primary labels (>=15)', () => {
    75→      // Create properly initialized result
    76→      const result = createClassificationResult('test-123', 'session-123', 0);
    77→
    78→      // Populate with high confidence classification data
    79→      result.selectedLabels = [
    80→        {
    81→          category: 'financial',
    82→          confidence: 16.5,
    83→          score: 16.5,
    84→          isPrimary: true,
    85→          labelOrder: 1,
    86→          subtype: 'statement',
    87→          selectionRationale: 'High confidence financial classification',
    88→        },
    89→      ];
    90→      result.candidateScores = {
    91→        financial: { score: 16.5, confidence: 16.5, decision: 'selected' },
    92→      };
    93→
    94→      // Execute stage - mutates result in place
    95→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
    96→
    97→      // Verify routing decision
    98→      expect(result.needsAiClassification).toBe(false);
    99→      expect(result.explainabilityTrace.aiRouting).toBeDefined();
   100→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
   101→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('High confidence');
   102→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
   103→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('16.5');
   104→      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
   105→      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);
   106→    });
   107→
   108→    it('should skip AI when hard assertion condition is met', () => {
   109→      const result = createClassificationResult('test-123', 'session-123', 0);
   110→      result.selectedLabels = [
   111→        {
   112→          category: 'financial',
   113→          confidence: 12.0,
   114→          score: 12.0,
   115→          isPrimary: true,
   116→          labelOrder: 1,
   117→          subtype: 'statement',
   118→          selectionRationale: 'Hard assertion based on domain match',
   119→        },
   120→      ];
   121→      result.candidateScores = {
   122→        financial: { score: 12.0, confidence: 12.0, decision: 'selected', hardAssertion: true },
   123→      };
   124→
   125→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   126→
   127→      expect(result.needsAiClassification).toBe(false);
   128→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
   129→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('hard assertion');
   130→    });
   131→  });
   132→
   133→  describe('Medium Confidence Routing', () => {
   134→    it('should route to AI for medium confidence scores (8-14)', () => {
   135→      const result = createClassificationResult('test-123', 'session-123', 0);
   136→      result.selectedLabels = [
   137→        {
   138→          category: 'actionable',
   139→          confidence: 10.5,
   140→          score: 10.5,
   141→          isPrimary: true,
   142→          labelOrder: 1,
   143→          subtype: 'implicitAction',
   144→          selectionRationale: 'Medium confidence actionable classification',
   145→        },
   146→      ];
   147→      result.candidateScores = {
   148→        actionable: { score: 10.5, confidence: 10.5, decision: 'selected' },
   149→        personal: { score: 8.2, confidence: 8.2, decision: 'candidate' },
   150→      };
   151→
   152→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   153→
   154→      expect(result.needsAiClassification).toBe(true);
   155→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   156→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
   157→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('actionable');
   158→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('10.5');
   159→    });
   160→
   161→    it('should route to AI when multiple labels are selected', () => {
   162→      const result = createClassificationResult('test-123', 'session-123', 0);
   163→      result.selectedLabels = [
   164→        {
   165→          category: 'financial',
   166→          confidence: 12.0,
   167→          score: 12.0,
   168→          isPrimary: true,
   169→          labelOrder: 1,
   170→          subtype: 'receipt',
   171→          selectionRationale: 'Primary financial classification',
   172→        },
   173→        {
   174→          category: 'actionable',
   175→          confidence: 9.5,
   176→          score: 9.5,
   177→          isPrimary: false,
   178→          labelOrder: 2,
   179→          subtype: 'implicitAction',
   180→          selectionRationale: 'Secondary actionable classification',
   181→        },
   182→      ];
   183→      result.candidateScores = {
   184→        financial: { score: 12.0, confidence: 12.0, decision: 'selected' },
   185→        actionable: { score: 9.5, confidence: 9.5, decision: 'selected' },
   186→      };
   187→
   188→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   189→
   190→      expect(result.needsAiClassification).toBe(true);
   191→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   192→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('multiple labels');
   193→    });
   194→
   195→    it('should route to AI when close competitors exist', () => {
   196→      const result = createClassificationResult('test-123', 'session-123', 0);
   197→      result.selectedLabels = [
   198→        {
   199→          category: 'commerceLogistics',
   200→          confidence: 11.0,
   201→          score: 11.0,
   202→          isPrimary: true,
   203→          labelOrder: 1,
   204→          subtype: 'shippingUpdate',
   205→          selectionRationale: 'Close competition with travel category',
   206→        },
   207→      ];
   208→      result.candidateScores = {
   209→        commerceLogistics: { score: 11.0, confidence: 11.0, decision: 'selected' },
   210→        travel: { score: 9.5, confidence: 9.5, decision: 'candidate' },
   211→        personal: { score: 8.8, confidence: 8.8, decision: 'candidate' },
   212→      };
   213→
   214→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   215→
   216→      expect(result.needsAiClassification).toBe(true);
   217→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   218→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('close competing categories');
   219→    });
   220→  });
   221→
   222→  describe('Low Confidence Routing', () => {
   223→    it('should skip AI for very low confidence scores (<3)', () => {
   224→      const result = createClassificationResult('test-123', 'session-123', 0);
   225→      result.selectedLabels = [
   226→        {
   227→          category: 'uncategorized',
   228→          confidence: 2.1,
   229→          score: 2.1,
   230→          isPrimary: true,
   231→          labelOrder: 1,
   232→          subtype: 'needsReview',
   233→          selectionRationale: 'Very low confidence classification',
   234→        },
   235→      ];
   236→      result.candidateScores = {
   237→        uncategorized: { score: 2.1, confidence: 2.1, decision: 'selected' },
   238→      };
   239→
   240→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   241→
   242→      expect(result.needsAiClassification).toBe(false);
   243→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
   244→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Very low confidence');
   245→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('likely unclassifiable');
   246→    });
   247→
   248→    it('should skip AI for scores below AI routing threshold but above low threshold', () => {
   249→      const result = createClassificationResult('test-123', 'session-123', 0);
   250→      result.selectedLabels = [
   251→        {
   252→          category: 'systemNotifications',
   253→          confidence: 6.5,
   254→          score: 6.5,
   255→          isPrimary: true,
   256→          labelOrder: 1,
   257→          subtype: 'serviceStatus',
   258→          selectionRationale: 'Below AI routing threshold',
   259→        },
   260→      ];
   261→      result.candidateScores = {
   262→        systemNotifications: { score: 6.5, confidence: 6.5, decision: 'selected' },
   263→      };
   264→
   265→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   266→
   267→      expect(result.needsAiClassification).toBe(false);
   268→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('skipAi');
   269→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('below AI routing threshold');
   270→    });
   271→  });
   272→
   273→  describe('No Labels Selected', () => {
   274→    it('should route to AI when no labels are selected', () => {
   275→      const result = createClassificationResult('test-123', 'session-123', 0);
   276→      result.selectedLabels = [];
   277→      result.candidateScores = {};
   278→
   279→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   280→
   281→      expect(result.needsAiClassification).toBe(true);
   282→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   283→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('No labels selected');
   284→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('AI classification may recover');
   285→    });
   286→  });
   287→
   288→  describe('Edge Cases and Error Handling', () => {
   289→    it('should handle missing primary label gracefully', () => {
   290→      const result = createClassificationResult('test-123', 'session-123', 0);
   291→      result.selectedLabels = [
   292→        {
   293→          category: 'financial',
   294→          confidence: 10.0,
   295→          score: 10.0,
   296→          isPrimary: false,
   297→          labelOrder: 1,
   298→          subtype: 'receipt',
   299→          selectionRationale: 'No primary flag set',
   300→        },
   301→      ];
   302→      result.candidateScores = {
   303→        financial: { score: 10.0, confidence: 10.0, decision: 'selected' },
   304→      };
   305→
   306→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   307→
   308→      // Should use first label as primary when no primary flag is set
   309→      expect(result.needsAiClassification).toBe(true);
   310→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   311→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
   312→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('financial');
   313→    });
   314→
   315→    it('should handle malformed classification input', () => {
   316→      const result = createClassificationResult('test-123', 'session-123', 0);
   317→      result.selectedLabels = [
   318→        {
   319→          category: 'financial',
   320→          confidence: NaN,
   321→          score: NaN,
   322→          isPrimary: true,
   323→          labelOrder: 1,
   324→          subtype: 'receipt',
   325→          selectionRationale: 'Invalid confidence score',
   326→        },
   327→      ];
   328→      result.candidateScores = {};
   329→
   330→      expect(() => {
   331→        aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   332→      }).toThrow('Invalid confidence score');
   333→    });
   334→
   335→    it('should handle custom confidence thresholds', () => {
   336→      const customConfig = {
   337→        ...mockConfig,
   338→        settings: {
   339→          aiRouting: {
   340→            highConfidenceThreshold: 20,
   341→            aiRequiredThreshold: 10,
   342→            skipAiConditions: [],
   343→          },
   344→        },
   345→      };
   346→
   347→      const result = createClassificationResult('test-123', 'session-123', 0);
   348→      result.selectedLabels = [
   349→        {
   350→          category: 'financial',
   351→          confidence: 18.0,
   352→          score: 18.0,
   353→          isPrimary: true,
   354→          labelOrder: 1,
   355→          subtype: 'statement',
   356→          selectionRationale: 'High confidence with custom thresholds',
   357→        },
   358→      ];
   359→      result.candidateScores = {
   360→        financial: { score: 18.0, confidence: 18.0, decision: 'selected' },
   361→      };
   362→
   363→      aiRoutingStage(mockEmail, mockSession, result, customConfig);
   364→
   365→      // With higher threshold (20), score of 18 should route to AI
   366→      expect(result.needsAiClassification).toBe(true);
   367→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   368→      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(20);
   369→    });
   370→  });
   371→
   372→  describe('Close Competitors Analysis', () => {
   373→    it('should correctly identify close competitors within gap threshold', () => {
   374→      const result = createClassificationResult('test-123', 'session-123', 0);
   375→      result.selectedLabels = [
   376→        {
   377→          category: 'travel',
   378→          confidence: 12.0,
   379→          score: 12.0,
   380→          isPrimary: true,
   381→          labelOrder: 1,
   382→          subtype: 'flightAlert',
   383→          selectionRationale: 'Travel with commerce logistics competition',
   384→        },
   385→      ];
   386→      result.candidateScores = {
   387→        travel: { score: 12.0, confidence: 12.0, decision: 'selected' },
   388→        commerceLogistics: { score: 10.5, confidence: 10.5, decision: 'candidate' },
   389→        personal: { score: 9.8, confidence: 9.8, decision: 'candidate' },
   390→        financial: { score: 4.0, confidence: 4.0, decision: 'rejected' },
   391→      };
   392→
   393→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   394→
   395→      expect(result.needsAiClassification).toBe(true);
   396→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   397→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('close competing categories');
   398→    });
   399→
   400→    it('should not consider distant competitors as close', () => {
   401→      const result = createClassificationResult('test-123', 'session-123', 0);
   402→      result.selectedLabels = [
   403→        {
   404→          category: 'financial',
   405→          confidence: 14.0,
   406→          score: 14.0,
   407→          isPrimary: true,
   408→          labelOrder: 1,
   409→          subtype: 'statement',
   410→          selectionRationale: 'Clear financial with distant competitors',
   411→        },
   412→      ];
   413→      result.candidateScores = {
   414→        financial: { score: 14.0, confidence: 14.0, decision: 'selected' },
   415→        actionable: { score: 8.0, confidence: 8.0, decision: 'candidate' },
   416→        personal: { score: 6.0, confidence: 6.0, decision: 'candidate' },
   417→      };
   418→
   419→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   420→
   421→      expect(result.needsAiClassification).toBe(true);
   422→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   423→      expect(result.explainabilityTrace.aiRouting?.reason).not.toContain('close competing categories');
   424→    });
   425→  });
   426→
   427→  describe('Explainability and Audit Trail', () => {
   428→    it('should generate complete explainability trace', () => {
   429→      const result = createClassificationResult('test-123', 'session-123', 0);
   430→      result.selectedLabels = [
   431→        {
   432→          category: 'actionable',
   433→          confidence: 11.5,
   434→          score: 11.5,
   435→          isPrimary: true,
   436→          labelOrder: 1,
   437→          subtype: 'explicitAction',
   438→          selectionRationale: 'Action required classification',
   439→        },
   440→      ];
   441→      result.candidateScores = {
   442→        actionable: { score: 11.5, confidence: 11.5, decision: 'selected' },
   443→      };
   444→
   445→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   446→
   447→      expect(result.explainabilityTrace.aiRouting).toBeDefined();
   448→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   449→      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
   450→      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);
   451→      expect(result.explainabilityTrace.aiRouting?.skipConditions).toEqual([]);
   452→      expect(result.explainabilityTrace.aiRouting?.reason).toBeDefined();
   453→      expect(result.explainabilityTrace.stageTimings?.aiRouting).toBeDefined();
   454→      expect(result.explainabilityTrace.stageTimings?.aiRouting).toBeGreaterThanOrEqual(0);
   455→    });
   456→
   457→    it('should include threshold configuration in trace', () => {
   458→      const result = createClassificationResult('test-123', 'session-123', 0);
   459→      result.selectedLabels = [
   460→        {
   461→          category: 'subscriptionContent',
   462→          confidence: 13.0,
   463→          score: 13.0,
   464→          isPrimary: true,
   465→          labelOrder: 1,
   466→          subtype: 'newsletter',
   467→          selectionRationale: 'Newsletter classification',
   468→        },
   469→      ];
   470→      result.candidateScores = {
   471→        subscriptionContent: { score: 13.0, confidence: 13.0, decision: 'selected' },
   472→      };
   473→
   474→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   475→
   476→      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
   477→      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);
   478→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   479→      expect(result.explainabilityTrace.aiRouting?.reason).toContain('Medium confidence');
   480→    });
   481→  });
   482→
   483→  describe('Performance Requirements', () => {
   484→    it('should process routing decision in under 50ms', () => {
   485→      const result = createClassificationResult('test-123', 'session-123', 0);
   486→      result.selectedLabels = [
   487→        {
   488→          category: 'financial',
   489→          confidence: 12.5,
   490→          score: 12.5,
   491→          isPrimary: true,
   492→          labelOrder: 1,
   493→          subtype: 'receipt',
   494→          selectionRationale: 'Performance test classification',
   495→        },
   496→      ];
   497→      result.candidateScores = {
   498→        financial: { score: 12.5, confidence: 12.5, decision: 'selected' },
   499→      };
   500→
   501→      const startTime = Date.now();
   502→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   503→      const endTime = Date.now();
   504→
   505→      const processingTime = endTime - startTime;
   506→      expect(processingTime).toBeLessThan(50);
   507→      expect(result.explainabilityTrace.stageTimings?.aiRouting).toBeLessThan(50);
   508→    });
   509→
   510→    it('should handle large candidate score sets efficiently', () => {
   511→      const largeCandidateScores: Record<string, CandidateScore> = {};
   512→      for (let i = 0; i < 100; i++) {
   513→        largeCandidateScores[`category_${i}`] = {
   514→          score: Math.random() * 10,
   515→          confidence: Math.random() * 10,
   516→          decision: 'candidate',
   517→        };
   518→      }
   519→
   520→      const result = createClassificationResult('test-123', 'session-123', 0);
   521→      result.selectedLabels = [
   522→        {
   523→          category: 'financial',
   524→          confidence: 12.0,
   525→          score: 12.0,
   526→          isPrimary: true,
   527→          labelOrder: 1,
   528→          subtype: 'receipt',
   529→          selectionRationale: 'Large dataset test',
   530→        },
   531→      ];
   532→      result.candidateScores = largeCandidateScores;
   533→
   534→      const startTime = Date.now();
   535→      aiRoutingStage(mockEmail, mockSession, result, mockConfig);
   536→      const endTime = Date.now();
   537→
   538→      expect(endTime - startTime).toBeLessThan(100);
   539→      expect(result.explainabilityTrace.aiRouting?.routingDecision).toBe('fullClassification');
   540→    });
   541→  });
   542→
   543→  describe('Threshold Validation and Ordering', () => {
   544→    it('should use correct threshold ordering (low < aiRequired < high)', () => {
   545→      // Test low confidence threshold (3) - create new result for each test
   546→      const result1 = createClassificationResult('test-123', 'session-123', 0);
   547→      result1.selectedLabels = [
   548→        {
   549→          category: 'uncategorized',
   550→          confidence: 2.5,
   551→          score: 2.5,
   552→          isPrimary: true,
   553→          labelOrder: 1,
   554→          subtype: 'needsReview',
   555→          selectionRationale: 'Below low confidence threshold',
   556→        },
   557→      ];
   558→      result1.candidateScores = {
   559→        uncategorized: { score: 2.5, confidence: 2.5, decision: 'selected' },
   560→      };
   561→
   562→      aiRoutingStage(mockEmail, mockSession, result1, mockConfig);
   563→      expect(result1.needsAiClassification).toBe(false);
   564→      expect(result1.explainabilityTrace.aiRouting?.reason).toContain('Very low confidence');
   565→
   566→      // Test AI required threshold (12) - create new result
   567→      const result2 = createClassificationResult('test-456', 'session-123', 0);
