      // Verify threshold values are recorded in explainability trace
      expect(result.explainabilityTrace.aiRouting?.highConfidenceThreshold).toBe(15);
      expect(result.explainabilityTrace.aiRouting?.aiRequiredThreshold).toBe(12);

      // Verify routing decision is documented
      expect(result.explainabilityTrace.aiRouting?.reason).toBeDefined();
      expect(result.explainabilityTrace.aiRouting?.reason).not.toBe('');
    });
  });
