     1→/**
     2→ * AI Routing Stage
     3→ *
     4→ * Stage 8 of the EmailCategorizer pipeline. Determines whether emails need AI classification
     5→ * based on confidence scores from multi-label selection. Routes high-confidence emails directly
     6→ * to final decision while sending uncertain cases through AI classification for enhancement.
     7→ *
     8→ * ROUTING DECISION LOGIC:
     9→ * - High Confidence (>=15): Skip AI - rule-based results are reliable
    10→ * - Medium Confidence (8-14): Route to AI - can benefit from enhanced classification
    11→ * - Very Low Confidence (<3): Skip AI - likely unclassifiable even with AI
    12→ * - No Labels Selected: Route to AI - last chance for classification
    13→ * - Hard Assertions: Skip AI - domain-based results are authoritative
    14→ */
    15→
    16→import { EmailMessage, ClassificationSession } from '../types';
    17→import { ClassificationResult, SelectedLabel, CandidateScore } from '../types/classification-result';
    18→import { ConfidenceThresholds } from './types';
    19→import {
    20→  validateEmailInput,
    21→  validateSessionInput,
    22→  validateConfigInput,
    23→  validateConfidenceScore,
    24→} from '../utils/validation';
    25→
    26→/**
    27→ * AI Routing Configuration
    28→ *
    29→ * THREE-THRESHOLD LOGIC for AI routing decisions:
    30→ *
    31→ * 1. highConfidenceThreshold: Score >= this → Skip AI (rule-based result reliable)
    32→ *    - Example: score = 0.9, highThreshold = 0.8 → Skip AI (confident in rules)
    33→ *
    34→ * 2. lowConfidenceThreshold: Score < this → Skip AI (too uncertain for AI to help)
    35→ *    - Example: score = 0.2, lowThreshold = 0.3 → Skip AI (likely unclassifiable)
    36→ *
    37→ * 3. aiRequiredThreshold: Within medium range, score >= this → Route to AI
    38→ *    - Medium confidence range: lowConfidenceThreshold <= score < highConfidenceThreshold
    39→ *    - Example: score = 0.6, aiRequired = 0.5, low = 0.3, high = 0.8 → Route to AI
    40→ *    - Example: score = 0.4, aiRequired = 0.5, low = 0.3, high = 0.8 → Skip AI (not worth cost)
    41→ *
    42→ * THRESHOLD ORDERING REQUIREMENT: low < aiRequired < high
    43→ *
    44→ * AI ROUTING DECISION FLOW:
    45→ * - IF score >= highConfidenceThreshold → Skip AI (high confidence)
    46→ * - ELSE IF score < lowConfidenceThreshold → Skip AI (very low confidence)
    47→ * - ELSE IF lowConfidenceThreshold <= score < highConfidenceThreshold (medium confidence):
    48→ *   - IF score >= aiRequiredThreshold → Route to AI (worth the cost)
    49→ *   - ELSE → Skip AI (below cost threshold)
    50→ */
    51→export interface AIRoutingConfig {
    52→  settings: {
    53→    aiRouting: {
    54→      highConfidenceThreshold: number;
    55→      aiRequiredThreshold: number;
    56→      skipAiConditions: string[];
    57→    };
    58→  };
    59→  confidenceThresholds: ConfidenceThresholds & {
    60→    aiClassificationRequired?: number;
    61→  };
    62→}
    63→
    64→// Routing decision result
    65→export interface RoutingDecision {
    66→  routeToAi: boolean;
    67→  routingReason: string;
    68→  confidenceAssessment: string;
    69→  costConsideration: string;
    70→}
    71→
    72→// Simplified explainability trace for AI routing
    73→export interface AIRoutingExplainabilityTrace {
    74→  stageType: string;
    75→  stageOrder: number;
    76→  decisionFactors: {
    77→    primaryScore: number;
    78→    thresholdAnalysis: {
    79→      highConfidenceThreshold: number;
    80→      aiRequiredThreshold: number;
    81→      lowConfidenceThreshold: number;
    82→      primaryScore: number;
    83→      thresholdMet: string;
    84→    };
    85→    competitorAnalysis: {
    86→      closeCompetitorsFound: boolean;
    87→      competitorCount: number;
    88→      multipleLabelsSelected: boolean;
    89→    };
    90→  };
    91→  reasoning: string;
    92→  processingMetadata: {
    93→    processingTimeMs: number;
    94→    inputLabelsCount: number;
    95→    candidateScoresCount: number;
    96→  };
    97→}
    98→
    99→// Stage result interface
   100→export interface AIRoutingResult {
   101→  routingDecision: RoutingDecision;
   102→  routingBranch: 'aiClassification' | 'directToMerge';
   103→  explainabilityTrace: AIRoutingExplainabilityTrace;
   104→}
   105→
   106→/**
   107→ * AI Routing Stage Implementation
   108→ *
   109→ * Analyzes classification confidence and determines optimal routing strategy
   110→ * for email processing continuation.
   111→ *
   112→ * CANONICAL SIGNATURE: (email, session, result, config) => void
   113→ * Mutates result.needsAiClassification and adds explainability trace
   114→ */
   115→export function aiRoutingStage(
   116→  email: EmailMessage,
   117→  session: ClassificationSession,
   118→  result: ClassificationResult,
   119→  config: AIRoutingConfig
   120→): void {
   121→  const startTime = Date.now();
   122→
   123→  // Validate inputs
   124→  validateInputs(email, session, result, config);
   125→
   126→  // Extract data from result object
   127→  const selectedLabels = result.selectedLabels;
   128→  const candidateScores = result.candidateScores;
   129→
   130→  // Extract routing thresholds with fallbacks
   131→  const highConfidenceThreshold =
   132→    config.settings.aiRouting.highConfidenceThreshold || config.confidenceThresholds.highConfidence || 15;
   133→
   134→  const aiRequiredThreshold = config.confidenceThresholds.mediumConfidence || 8;
   135→
   136→  const lowConfidenceThreshold = config.confidenceThresholds.lowConfidence || 3;
   137→
   138→  const skipAiConditions = config.settings.aiRouting.skipAiConditions || [];
   139→
   140→  // Make routing decision
   141→  const routingDecision = makeRoutingDecision(
   142→    selectedLabels,
   143→    candidateScores,
   144→    highConfidenceThreshold,
   145→    aiRequiredThreshold,
   146→    lowConfidenceThreshold,
   147→    skipAiConditions
   148→  );
   149→
   150→  // Generate explainability trace
   151→  const explainabilityTrace = generateExplainabilityTrace(
   152→    selectedLabels,
   153→    candidateScores,
   154→    routingDecision,
   155→    {
   156→      highConfidenceThreshold: highConfidenceThreshold,
   157→      aiRequiredThreshold:
   158→        config.settings.aiRouting.aiRequiredThreshold || config.confidenceThresholds.aiClassificationRequired || 12,
   159→      lowConfidenceThreshold: lowConfidenceThreshold,
   160→    },
   161→    startTime
   162→  );
   163→
   164→  // Mutate result in place
   165→  result.needsAiClassification = routingDecision.routeToAi;
   166→
   167→  // Initialize explainabilityTrace if not exists (defensive check)
   168→  if (!result.explainabilityTrace) {
   169→    throw new Error('CRITICAL: explainabilityTrace is not initialized in result object');
   170→  }
   171→
   172→  // Add explainability trace to result - store in appropriate field
   173→  if (!result.explainabilityTrace.aiRouting) {
   174→    result.explainabilityTrace.aiRouting = {
   175→      routingDecision: routingDecision.routeToAi ? 'fullClassification' : 'skipAi',
   176→      highConfidenceThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.highConfidenceThreshold,
   177→      aiRequiredThreshold: explainabilityTrace.decisionFactors.thresholdAnalysis.aiRequiredThreshold,
   178→      skipConditions: [],
   179→      reason: routingDecision.routingReason,
   180→    };
   181→  }
   182→
   183→  // Track processing time
   184→  result.explainabilityTrace.stageTimings = result.explainabilityTrace.stageTimings || {};
   185→  result.explainabilityTrace.stageTimings['aiRouting'] = explainabilityTrace.processingMetadata.processingTimeMs;
   186→}
   187→
   188→/**
   189→ * Validate input parameters
   190→ */
   191→function validateInputs(
   192→  email: EmailMessage,
   193→  session: ClassificationSession,
   194→  result: ClassificationResult,
   195→  config: AIRoutingConfig
   196→): void {
   197→  validateEmailInput(email);
   198→  validateSessionInput(session);
   199→  validateConfigInput(config);
   200→
   201→  if (!result) {
   202→    throw new Error('Classification result is required');
   203→  }
   204→
   205→  if (!result.selectedLabels) {
   206→    throw new Error('Selected labels are required in result');
   207→  }
   208→
   209→  if (!result.candidateScores) {
   210→    throw new Error('Candidate scores are required in result');
   211→  }
   212→
   213→  // Validate confidence scores
   214→  for (const label of result.selectedLabels) {
   215→    validateConfidenceScore(label.confidence);
   216→  }
   217→}
   218→
   219→/**
   220→ * Core routing decision logic
   221→ *
   222→ * Implements the three-threshold AI routing strategy:
   223→ * - High confidence (>= highThreshold): Skip AI - rule-based results are reliable
   224→ * - Low confidence (< lowThreshold): Skip AI - too uncertain for AI to help
   225→ * - Medium confidence (lowThreshold <= score < highThreshold):
   226→ *   - If score >= aiRequiredThreshold: Route to AI (worth the cost)
   227→ *   - Otherwise: Skip AI (below cost threshold)
   228→ *
   229→ * @param selectedLabels - Labels selected by multi-label selection stage
   230→ * @param candidateScores - All candidate category scores
   231→ * @param highConfidenceThreshold - Skip AI if score >= this (confident in rules)
   232→ * @param aiRequiredThreshold - Within medium range, route to AI if score >= this
   233→ * @param lowConfidenceThreshold - Skip AI if score < this (too uncertain)
   234→ * @param skipAiConditions - Additional conditions to skip AI (e.g., hardAssertion)
